+                      {worker.status}
+                    </div>
+                  </div>
+                </button>
+              );
+            })
+          )}
+
+          {isAtMax && (
+            <div className="px-3 py-2 text-xs text-muted-foreground border-t border-border mt-1">
+              Maximum {maxSelection} workers can be selected
+            </div>
+          )}
+        </div>
+      )}
+    </div>
+  );
+}
+
+export type { WorkerSelectorProps };

